import{_ as o,r as i,o as l,c,b as e,e as a,w as t,d as n,f as r}from"./app-55c326ac.js";const p={},u=e("h1",{id:"_07-dockerfile指令详解",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#_07-dockerfile指令详解","aria-hidden":"true"},"#"),n(" 07. Dockerfile指令详解")],-1),v={class:"table-of-contents"},m=r(`<p><strong>前言</strong> Dockerfile提供了十多个指令，如<code>FROM</code>;<code>RUN</code>;<code>COPY</code>;<code>ADD</code>;<code>CMD</code>;<code>ENTRYPOINT</code>;<code>ENV</code>等等</p><hr><h2 id="copy-复制文件" tabindex="-1"><a class="header-anchor" href="#copy-复制文件" aria-hidden="true">#</a> COPY 复制文件</h2><p><strong>格式</strong>：</p><ul><li><code>COPY [--chown=&lt;user&gt;:&lt;group&gt;]&lt;源路径&gt;...&lt;目标路径&gt;</code></li><li><code>COPY [--chown=&lt;user&gt;:&lt;group&gt;][&quot;&lt;源路径&gt;&quot;,...&quot;&lt;目标路径&gt;&quot;]</code></li></ul><p>和<code>RUN</code>指令一样，也有两种格式，一种类似于命令行，一种类似于函数调用<br><code>COPY</code>指令将从构建上下文目录中<code>&lt;源路径&gt;</code>的文件/目录复制到新的一层的镜像内的<code>&lt;目标路径&gt;</code>位置。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>COPY package.json /usr/src/app/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>&lt;源路径&gt;</code>可以是多个，甚至可以使通配符，其通配符规则要满足Go的<code>filepath.Match</code>规则</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>COPY hom* /mydir/
COPY hom?.txt /mydir/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>&lt;目标路径&gt;</code>可以是容器内的绝对路径，也可以是相对于工作目录的相对路径(工作目录可以用<code>WORKDIR</code>指令来指定)。目标路径不需要事先创建，如果目录不存在会在复制文件前先行创建缺失目录。</p><p>还需要<strong>注意</strong>,使用<code>COPY</code>指令，源文件的各种元数据都会保留。比如读、写、执行权限、文件变更时间等。这个特性对于镜像定制很有用。特别是构建相关文件都在使用Git进行管理的时候。</p><p>在使用该指令的时候还可以加上<code>--chrom=&lt;user&gt;:&lt;group&gt;</code>选项来改变文件的所属用户及所属组。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>COPY --chown=55:mygroup files* /mydir/
COPY --chown=bin files* /mydir/
COPY --choen=1 files* /mydir/
COPY --chown=10:11 files* /mydir/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="add更高级的复制文件" tabindex="-1"><a class="header-anchor" href="#add更高级的复制文件" aria-hidden="true">#</a> ADD更高级的复制文件</h2><p><code>ADD</code>指令和<code>COPY</code>的格式和性质基本一致。但是在<code>COPY</code>基础上增加了一些功能</p><p>比如<code>&lt;源路径&gt;</code>可以是一个<code>URL</code>，这种情况，Docker引擎会试图去下载这个链接的文件放到<code>&lt;目标路径&gt;</code> 去。下载后的文件权限自动设置为 600，如果这并不是想要的权限，那么还需要增加额外的一层 <code>RUN</code> 进行权限调整，另外，如果下载的是个压缩包，需要解压缩，也一样还需要额外的一层 RUN 指令进行解压缩。所以<strong>不如直接</strong>使用 RUN 指令，然后使用 wget 或者 curl 工具下载，处理权限、解压缩、然后清理无用文件更合理。<strong>因此，这个功能其实并不实用，而且不推荐使用。</strong></p><p>如果 <code>&lt;源路径&gt;</code> 为一个<code>tar</code>压缩文件的话，压缩格式为 gzip, bzip2 以及 xz 的情况下，<code>ADD</code>指令将会自动解压缩这个压缩文件到<code>&lt;目标路径&gt;</code>去。</p><p>在某些情况下，这个自动解压缩的功能非常有用，比如官方镜像 ubuntu 中：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>FROM scratch
ADD ubuntu-xenial-core-cloudimg-amd64-root.tar.gz /
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>**注意：**如果我们真的是希望复制个压缩文件进去，而不解压缩，这时就不可以使用<code>ADD</code>命令了。</p><p>尽可能的使用<code>COPY</code>，因为<code>COPY</code>的语义很明确，就是复制文件而已，而<code>ADD</code>则包含了更复杂的功能，其行为也不一定很清晰。最适合使用<code>ADD</code>的场合，就是所提及的需要自动解压缩的场合.</p><p><strong>注意：</strong><code>ADD</code>指令会令镜像构建缓存失败，从而可能会令镜像构建变得比较缓慢。</p><p>因此<code>COPY</code>和<code>ADD</code>指令中选择的时候，可以遵循：<strong>所有文件的复制均使用<code>COPY</code>指令，仅在需要自动解压缩的场合使用<code>ADD</code>。</strong></p><p>使用ADD指令的时候还可以机上<code>--chown=&lt;user&gt;:&lt;group&gt;</code>选项来改变文件的所属用户及所属组。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>ADD --chown=55:mygroup files* /mydir/
ADD --chown=bin files* /mydir/
ADD --chown=1 files* /mydir/
ADD --chown=10:11 files* /mydir/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="cmd-容器启动命令" tabindex="-1"><a class="header-anchor" href="#cmd-容器启动命令" aria-hidden="true">#</a> CMD 容器启动命令</h2><p><code>CMD</code> 指令的格式和 <code>RUN</code> 相似，也是两种格式：</p><ul><li>shell 格式：<code>CMD &lt;命令&gt;</code></li><li>exec 格式：<code>CMD [&quot;可执行文件&quot;, &quot;参数1&quot;, &quot;参数2&quot;...]</code></li></ul><p>参数列表格式：<code>CMD [&quot;参数1&quot;, &quot;参数2&quot;...]</code>。在指定了 <code>ENTRYPOINT</code> 指令后，用 CMD 指定具体的参数。</p><p>Docker 不是虚拟机，容器就是进程。既然是进程，那么在启动容器的时候，需要指定所运行的程序及参数。CMD 指令就是用于指定默认的容器主进程的启动命令的。</p><p>在运行时可以指定新的命令来替代镜像设置中的这个默认命令，比如，ubuntu 镜像默认的 <code>CMD</code> 是 <code>/bin/bash</code>，如果我们直接 <code>docker run -it ubuntu</code> 的话，会直接进入 <code>bash</code>。我们也可以在运行时指定运行别的命令，如 d<code>ocker run -it ubuntu cat /etc/os-release</code>。这就是用 <code>cat /etc/os-release</code> 命令替换了默认的 <code>/bin/bash</code> 命令了，输出了系统版本信息。</p><p>在指令格式上，一般推荐使用<code>exec</code>格式，这类格式在解析时会被解析为JSON数据，因此一定要使用双引号<code>&quot;</code>,而不要使用单引号。</p><p>使用<code>shell</code>格式的话，实际命令会被包装成 <code>sh -c</code>的参数的形式执行</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>CMD echo $HOME
在实际执行中，会将其变更为：
CMD [&quot;sh&quot;,&quot;-c&quot;,&quot;echo $HOME&quot;]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这就是为什么我们可以使用环境变量的原因，因为这些环境变量会被 shell 进行解析处理</p><p>提到 CMD 就不得不提容器中应用在前台执行和后台执行的问题。这是初学者常出现的一个混淆。</p><p>Docker 不是虚拟机，容器中的应用都应该以前台执行，而不是像虚拟机、物理机里面那样，用 upstart/systemd 去启动后台服务，容器内没有后台服务的概念。</p><p>对于容器而言，其启动程序就是容器应用进程，容器就是为了主进程而存在的，主进程退出，容器就失去了存在的意义，从而退出，其它辅助进程不是它需要关心的东西。</p><p>而使用 <code>service nginx start</code> 命令，则是希望 <code>upstart</code> 来以后台守护进程形式启动 <code>nginx</code> 服务。而刚才说了 <code>CMD service nginx start</code> 会被理解为 <code>CMD [ &quot;sh&quot;, &quot;-c&quot;, &quot;service nginx start&quot;]</code>，因此主进程实际上是 <code>sh</code>。那么当<code>service nginx start</code> 命令结束后，<code>sh</code> 也就结束了，<code>sh</code> 作为主进程退出了，自然就会令容器退出。</p><p>正确的做法是直接执行 <code>nginx</code> 可执行文件，并且要求以前台形式运行。比如：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>CMD [&quot;nginx&quot;, &quot;-g&quot;, &quot;daemon off;&quot;]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><hr><h2 id="entrypoint-入口点" tabindex="-1"><a class="header-anchor" href="#entrypoint-入口点" aria-hidden="true">#</a> ENTRYPOINT 入口点</h2><p>ENTRYPOINT的格式和RUN指定格式一样，分为<code>exec</code>和<code>shell</code>格式</p><p>ENTRYPOINT的目的和CMD一样，都是在指定容器启动程序及参数。ENTRYPOINT在运行时也可以替换，不过比CMD要略显繁琐，需要通过docker run的参数--entrypoint来指定</p><p>当指定ENTRYPOINT后，CMD的含义就发生了改变，不再是直接的运行其命令，而是将CMD的内容作为参数传给ENTRYPOINT指定，就是说，实际执行是变为：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>&lt;ENTRYPOINT&gt; &quot;&lt;CMD&gt;&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="使用entrypoint的好处" tabindex="-1"><a class="header-anchor" href="#使用entrypoint的好处" aria-hidden="true">#</a> 使用ENTRYPOINT的好处</h3><h4 id="一、让镜像变成想命令一样使用" tabindex="-1"><a class="header-anchor" href="#一、让镜像变成想命令一样使用" aria-hidden="true">#</a> 一、让镜像变成想命令一样使用</h4><p><strong>用<code>CMD</code>实现：活得自己当前公网IP的镜像</strong></p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>FROM ubuntu:18.04
RUN apt-get update\\
    &amp;&amp; apt-get install -y curl\\
    &amp;&amp; rm -rf /var/lib/apt/lists/*
CMD [&quot;curl&quot;,&quot;-s&quot;,&quot;https://ip.cn&quot;]

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 使用docker build -t myip构建镜像，当需要查询当前公网IP，只需要执行：</span>
<span class="token function">docker</span> build <span class="token parameter variable">-t</span> myip        <span class="token comment">#在Dockerfile文件所在目录构建myip镜像</span>
<span class="token function">docker</span> run myip             <span class="token comment">#执行镜像中的命令(CMD/ENTRYPOINT)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但当需要通过上面的镜像，希望获取HTTP头信息，就需加上-i参数，加上-i参数的结果呢：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> rum myip <span class="token parameter variable">-i</span>
docker: Error response from daemon: invalid header field value <span class="token string">&quot;oci runtime error: container_linux.go:247: starting container process caused <span class="token entity" title="\\&quot;">\\&quot;</span>exec: <span class="token entity" title="\\\\">\\\\</span><span class="token entity" title="\\&quot;">\\&quot;</span>-i<span class="token entity" title="\\\\">\\\\</span><span class="token entity" title="\\&quot;">\\&quot;</span>: executable file not found in <span class="token environment constant">$PATH</span><span class="token entity" title="\\&quot;">\\&quot;</span><span class="token entity" title="\\n">\\n</span>&quot;</span><span class="token builtin class-name">.</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>会报错（执行文件找不到）。 我们知道，跟在镜像名后面的是 <code>command</code>，运行时会替换 <code>CMD</code> 的默认值。因此这里的 <code>-i</code> 替换了原来的 <code>CMD</code>，而不是添加在原来的 <code>curl -s https://ip.cn</code> 后面。而 <code>-i</code>根本不是命令，所以自然找不到。</p><p>当希望加入-i参数，就必须输入完整的命令</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> rum myip <span class="token function">curl</span> <span class="token parameter variable">-i</span>  <span class="token parameter variable">-s</span> https://ip.cn
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>但当使用ENTRYPOINT就比较方便解决，用ENTRYPOINT重新定义镜像:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>FROM ubuntu:18.04
RUN apt-get update\\
    &amp;&amp; apt-get install -y curl\\
    &amp;&amp; rm -rf /var/lib/apt/lists/*
ENTRYPOINT [&quot;curl&quot;,&quot;-s&quot;,&quot;https://ip.cn&quot;]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>在尝试使用docker run myip -i：
<span class="token function">docker</span> run myip
<span class="token function">docker</span> run myip <span class="token parameter variable">-i</span>
<span class="token comment">## 说明：可以看到，这次成功了。这是因为当存在 ENTRYPOINT 后，CMD 的内容将会作为参数传给 ENTRYPOINT，而这里 -i 就是新的 CMD，因此会作为参数传给 curl，从而达到了我们预期的效果。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="引用运行前的准备工作" tabindex="-1"><a class="header-anchor" href="#引用运行前的准备工作" aria-hidden="true">#</a> 引用运行前的准备工作</h4><p>启动容器就是启动主进程，但有些时候，启动主进程前，需要一些准备工作。</p><p>比如 mysql 类的数据库，可能需要一些数据库配置、初始化的工作，这些工作要在最终的 mysql 服务器运行之前解决。</p><p>此外，可能希望避免使用 root 用户去启动服务，从而提高安全性，而在启动服务前还需要以 root 身份执行一些必要的准备工作，最后切换到服务用户身份启动服务。或者除了服务外，其它命令依旧可以使用 root 身份执行，方便调试等。</p><p><strong>这些准备工作是和容器 CMD 无关的，无论 CMD 为什么，都需要事先进行一个预处理的工作</strong>。这种情况下，可以写一个脚本，然后放入 ENTRYPOINT 中去执行，而这个脚本会将接到的参数（也就是 <code>&lt;CMD&gt;</code>）作为命令，在脚本最后执行<br> 比如官方镜像redis中的例子：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>FROM alpine:3.4
...
RUN addgroup -S redis &amp;&amp; adduser -S -G redis redis
...
ENTRYPOINT [&quot;docker-entrypoint.sh&quot;]

EXPOSE 6379         #暴露端口
CMD [&quot;redis-server&quot;]

##可以看到其中为了redis服务创建了redis用户，并在最后指定了ENTRYPOINT为docker-entrypoint.sh脚本
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token shebang important">#!/bin/bash</span>
<span class="token punctuation">..</span>.
<span class="token comment"># allow the container to be started with \`--user\`</span>
<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$1</span>&quot;</span> <span class="token operator">=</span> <span class="token string">&#39;redis-server&#39;</span> <span class="token parameter variable">-a</span> <span class="token string">&quot;<span class="token variable"><span class="token variable">$(</span><span class="token function">id</span> <span class="token parameter variable">-u</span><span class="token variable">)</span></span>&quot;</span> <span class="token operator">=</span> <span class="token string">&#39;0&#39;</span><span class="token punctuation">]</span><span class="token punctuation">;</span><span class="token keyword">then</span>
    <span class="token function">chown</span> <span class="token parameter variable">-R</span> redis <span class="token builtin class-name">.</span>
    <span class="token builtin class-name">exec</span> su-exec redis <span class="token string">&quot;<span class="token variable">$0</span>&quot;</span> <span class="token string">&quot;<span class="token variable">$@</span>&quot;</span>
<span class="token keyword">fi</span>

<span class="token builtin class-name">exec</span> <span class="token string">&quot;<span class="token variable">$@</span>&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面的脚本内容就是根据CMD的内容来判断，如果是redis-server的话。则切换到redis用户身份启动服务器，否则依旧使用root身份执行。比如：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-it</span> redis <span class="token function">id</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><hr><h2 id="env-设置环境变量" tabindex="-1"><a class="header-anchor" href="#env-设置环境变量" aria-hidden="true">#</a> ENV 设置环境变量</h2><p>格式有两种：</p><ul><li><code>ENV &lt;key&gt; &lt;value&gt;</code></li><li><code>ENV &lt;key1&gt;=&lt;value1&gt; &lt;key2&gt;=&lt;value2&gt;...</code> 这个指令很简单，就是设置环境变量而已，无论是后面的其它指令，如 RUN，还是运行时的应用，都可以直接使用这里定义的环境变量。</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>ENV VERSION=1.0 DEBUG=on \\
    NAME=&quot;Happy Feet&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>这个例子中演示了如何换行，以及对含有空格的值用双引号括起来的办法，这和 Shell 下的行为是一致的</p><p>使用ENV环境变量，能够是Dockerfile构建维护变得方便</p><p>下列指令可以支持环境变量展开： ADD、COPY、ENV、EXPOSE、LABEL、USER、WORKDIR、VOLUME、STOPSIGNAL、ONBUILD。</p><p>可以从这个指令列表里感觉到，环境变量可以使用的地方很多，很强大。通过环境变量，我们可以让一份 Dockerfile 制作更多的镜像，只需使用不同的环境变量即可。</p><hr><h2 id="volume-定义匿名卷" tabindex="-1"><a class="header-anchor" href="#volume-定义匿名卷" aria-hidden="true">#</a> VOLUME 定义匿名卷</h2><p>格式：</p><ul><li><code>VOlUME [&quot;&lt;路径1&gt;&quot;,&quot;&lt;路径2&gt;&quot;]</code></li><li><code>VOLUME &lt;路径&gt;</code></li></ul><p>容器运行时，应该尽量保持容器存储层不发生写操作，对于数据库类需要保存动态数据的应用，其数据库文件应该保存于卷中，为防止运行忘记将动态文件所保存目录挂载为卷，在Dockerfile中，可以事先指定某些目录挂载为匿名卷，这样在运行时当用户不指定挂载，其应用也可以正常运行，不会像容器存储层写入大量数据。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>VOLUME  /date
##说明：这里的/date目录，就会在运行时自动挂载为匿名卷，任何像/date中写入的信息都不会记录进容器存储层。
##从而保证容器存储层的无状态华。当然，运行时可以覆盖这个挂载设置。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">-v</span> mydata:/data xxxx

<span class="token comment">##说明：这里，使用了mydata这个命名卷挂载到了/data这个位置，替代了Dockerfile中定义的匿名卷的挂载配置。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="expose-声明-暴露-端口" tabindex="-1"><a class="header-anchor" href="#expose-声明-暴露-端口" aria-hidden="true">#</a> EXPOSE 声明（暴露）端口</h2><p>格式： <code>EXPOSE &lt;端口1&gt; [&lt;端口2&gt;...]</code></p><p>EXPOSE 指令是声明运行时容器提供服务端口，这只是一个声明，在运行时并不会因为这个声明应用就会开启这个端口的服务。在 Dockerfile 中写入这样的声明有<strong>两个好处</strong></p><ul><li>一个是帮助镜像使用者理解这个镜像服务的守护端口，以方便配置映射</li><li>另一个用处则是在运行时使用随机端口映射时，也就是 docker run -P 时，会自动随机映射 EXPOSE 的端口。</li></ul><p>要将 EXPOSE 和在运行时使用 <code>-p &lt;宿主端口&gt;:&lt;容器端口&gt;</code> 区分开来。-p，是映射宿主端口和容器端口，换句话说，就是将容器的对应端口服务公开给外界访问，而 EXPOSE 仅仅是声明容器打算使用什么端口而已，并不会自动在宿主进行端口映射。</p><hr><h2 id="workdir-指定工作目录" tabindex="-1"><a class="header-anchor" href="#workdir-指定工作目录" aria-hidden="true">#</a> WORKDIR 指定工作目录</h2><p>格式： <code>WORKDIR &lt;工作目录路径&gt;</code></p><p>使用 WORKDIR 指令可以来指定工作目录（或者称为当前目录），以后各层的当前目录就被改为指定的目录，如该目录不存在，WORKDIR 会帮你建立目录。</p><p>之前提到一些初学者常犯的错误是把 Dockerfile 等同于 Shell 脚本来书写，这种错误的理解还可能会导致出现下面这样的错误：</p><p>RUN cd /app RUN echo &quot;hello&quot; &gt; world.txt 如果将这个 Dockerfile 进行构建镜像运行后，会发现找不到 /app/world.txt 文件，或者其内容不是 hello。原因其实很简单，在 Shell 中，连续两行是同一个进程执行环境，因此前一个命令修改的内存状态，会直接影响后一个命令；而在 Dockerfile 中，这两行 RUN 命令的执行环境根本不同，是两个完全不同的容器。这就是对 Dockerfile 构建分层存储的概念不了解所导致的错误。</p><p>之前说过每一个 RUN 都是启动一个容器、执行命令、然后提交存储层文件变更。第一层 RUN cd /app 的执行仅仅是当前进程的工作目录变更，一个内存上的变化而已，其结果不会造成任何文件变更。而到第二层的时候，启动的是一个全新的容器，跟第一层的容器更完全没关系，自然不可能继承前一层构建过程中的内存变化。</p><p>因此如果需要改变以后各层的工作目录的位置，那么应该使用 WORKDIR 指令。</p><hr><h2 id="user指定当前用户" tabindex="-1"><a class="header-anchor" href="#user指定当前用户" aria-hidden="true">#</a> USER指定当前用户</h2><p>格式： <code>USER &lt;用户名&gt;:[&lt;用户组&gt;]</code> USER指定和WORKDIR相似，都是改变环境状态并影响以后的层<br> WORKDIR 是改变工作目录，USER 则是改变之后层的执行<code>RUN</code>,<code>CMD</code>以及 <code>ENTRYPOINT</code>这类命令的身份。<br> 和 WORKDIR 一样，USER 只是帮助你切换到指定用户而已，这个用户必须是事先建立好的，否则无法切换。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>RUN groupadd -r redis &amp;&amp; useradd -r -g redis redis 
USER redis
RUN [&quot;redis-server&quot;]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果以 root 执行的脚本，在执行期间希望改变身份，比如希望以某个已经建立好的用户来运行某个服务进程，<strong>不要</strong>使用 <code>su</code> 或者 <code>sudo</code>，这些都需要比较麻烦的配置，而且在 <code>TTY</code> 缺失的环境下经常出错。建议使用 <code>gosu</code>。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># 建立redis用户，并使用gosu换另一个用户执行命令
RUN groupadd -r redis &amp;&amp; useradd -r -g redis redis
# 下载gosu
RUN wget -O /usr/local/bin/gosu &quot;https://github.com/tianon/gosu/releases/download/1.7/gosu-amd64&quot; \\
    &amp;&amp; chmod +X /usr/local/bin/gosu \\
    $$ gosu nobody true
# 设置CMD，并以另外的用户执行
CMD [&quot;exec&quot;,&quot;gosu&quot;,&quot;redis&quot;,&quot;redis-server&quot;]
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="healthcheck-健康检查" tabindex="-1"><a class="header-anchor" href="#healthcheck-健康检查" aria-hidden="true">#</a> HEALTHCHECK 健康检查</h2><p>格式：</p><ul><li><code>HEALTHCHECK [选项] CMD &lt;命令&gt;</code>: 设置检查容器健康状态的命令</li><li><code>HEALTHCHECK NONE</code>: 如果基础镜像有健康检查指令，使用这行可以屏蔽掉漆健康检查</li></ul><p><code>HEALTHCHECK</code>指令是告诉Docker应该如何进行判断容器的状态是否正常。</p><p>在没有 HEALTHCHECK 指令前，Docker 引擎只可以通过容器内主进程是否退出来判断容器是否状态异常。很多情况下这没问题，但是如果程序进入死锁状态，或者死循环状态，应用进程并不退出，但是该容器已经无法提供服务了。在 1.12 以前，Docker 不会检测到容器的这种状态，从而不会重新调度，导致可能会有部分容器已经无法提供服务了却还在接受用户请求。</p><p>而自 1.12 之后，Docker 提供了 HEALTHCHECK 指令，通过该指令指定一行命令，用这行命令来判断容器主进程的服务状态是否还正常，从而比较真实的反应容器实际状态。</p><p>当在一个镜像指定了HEALTHCHECK指令后，用其启动容器，初始状态会为<code>starting</code>，在HEALTHCHECK指令检查成功后变为<code>healthy</code>,如果连续一定次数失败，则变为<code>unhealthy</code></p><p>HEALTHCHECK支持下面的选项</p><ul><li>--interval=&lt;间隔&gt; : 两次健康检查的间隔，默认为30秒</li><li>--timeout=&lt;时长&gt; : 健康检查命令运行超时时间，如果超过这个时间，本次健康检查被视为失败，默认30秒</li><li>--retries=&lt;次数&gt; : 当连续时报指定次数后，则将容器状态视为unhealthy,默认3次</li></ul><p>和CMD ENTERPOINT一样，HEALTHCHECK只可以出现一次，如果写了多个，只有最后一个生效。</p><p>在 <code>HEALTHCHECK [选项] CMD</code> 后面的命令，格式和 <code>ENTRYPOINT</code> 一样，分为 shell 格式，和 exec 格式。命令的返回值决定了该次健康检查的成功与否：<code>0</code>：成功；<code>1</code>：失败；<code>2</code>：保留，不要使用这个值。</p><p>例子：检查web服务是否正常开启</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token comment"># Dockerfile</span>
FROM nginx
RUN apt<span class="token punctuation">-</span>get update <span class="token important">&amp;&amp;</span> apt<span class="token punctuation">-</span>get install <span class="token punctuation">-</span>y curl <span class="token important">&amp;&amp;</span> rm <span class="token punctuation">-</span>rf /var/lib/apt/lists/*
HEALTHCHECK <span class="token punctuation">-</span><span class="token punctuation">-</span>interval=5s  <span class="token punctuation">-</span><span class="token punctuation">-</span>timeout=3s \\
CMD curl <span class="token punctuation">-</span>fs http<span class="token punctuation">:</span>//localhost/ <span class="token punctuation">|</span><span class="token punctuation">|</span> exit 1
<span class="token comment"># 说明：这里我们设置了每 5 秒检查一次（这里为了试验所以间隔非常短，实际应该相对较长），如果健康检查命令超过 3 秒没响应就视为失败，并且使用 curl -fs http://localhost/ || exit 1 作为健康检查命令</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> build <span class="token parameter variable">-t</span> myweb:v1 <span class="token builtin class-name">.</span>  <span class="token comment">#构建镜像</span>
<span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">--name</span> web <span class="token parameter variable">-p</span> <span class="token number">80</span>:80 myweb:v1  <span class="token comment">#启动容器</span>
<span class="token function">docker</span> container <span class="token function">ls</span>         <span class="token comment">#查看容器状态</span>
<span class="token function">docker</span> container <span class="token function">ls</span>         <span class="token comment">#查看容器状态</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但需要排除故障，健康检查命令的输出(包括 stdout 以及 stderr)都会被存储于健康状态里，可以用docker inspect进行查看</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> inspect <span class="token parameter variable">--format</span> <span class="token string">&#39;{{json .State.Health}}&#39;</span> web <span class="token operator">|</span> python <span class="token parameter variable">-m</span> json.tool
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h5 id="参考文档" tabindex="-1"><a class="header-anchor" href="#参考文档" aria-hidden="true">#</a> 参考文档</h5>`,125),b={href:"https://docs.docker.com/engine/reference/builder/",target:"_blank",rel:"noopener noreferrer"},h=e("br",null,null,-1),g={href:"https://docs.docker.com/develop/develop-images/dockerfile_best-practices/",target:"_blank",rel:"noopener noreferrer"},k=e("br",null,null,-1),x={href:"https://github.com/docker-library/docs",target:"_blank",rel:"noopener noreferrer"};function D(f,E){const s=i("router-link"),d=i("ExternalLinkIcon");return l(),c("div",null,[u,e("nav",v,[e("ul",null,[e("li",null,[a(s,{to:"#copy-复制文件"},{default:t(()=>[n("COPY 复制文件")]),_:1})]),e("li",null,[a(s,{to:"#add更高级的复制文件"},{default:t(()=>[n("ADD更高级的复制文件")]),_:1})]),e("li",null,[a(s,{to:"#cmd-容器启动命令"},{default:t(()=>[n("CMD 容器启动命令")]),_:1})]),e("li",null,[a(s,{to:"#entrypoint-入口点"},{default:t(()=>[n("ENTRYPOINT 入口点")]),_:1}),e("ul",null,[e("li",null,[a(s,{to:"#使用entrypoint的好处"},{default:t(()=>[n("使用ENTRYPOINT的好处")]),_:1})])])]),e("li",null,[a(s,{to:"#env-设置环境变量"},{default:t(()=>[n("ENV 设置环境变量")]),_:1})]),e("li",null,[a(s,{to:"#volume-定义匿名卷"},{default:t(()=>[n("VOLUME 定义匿名卷")]),_:1})]),e("li",null,[a(s,{to:"#expose-声明-暴露-端口"},{default:t(()=>[n("EXPOSE 声明（暴露）端口")]),_:1})]),e("li",null,[a(s,{to:"#workdir-指定工作目录"},{default:t(()=>[n("WORKDIR 指定工作目录")]),_:1})]),e("li",null,[a(s,{to:"#user指定当前用户"},{default:t(()=>[n("USER指定当前用户")]),_:1})]),e("li",null,[a(s,{to:"#healthcheck-健康检查"},{default:t(()=>[n("HEALTHCHECK 健康检查")]),_:1})])])]),m,e("blockquote",null,[e("p",null,[e("a",b,[n("Dockerfile官当文档"),a(d)]),h,e("a",g,[n("Dockerfile实践文档"),a(d)]),k,e("a",x,[n("Docker官方镜像"),a(d)])])])])}const C=o(p,[["render",D],["__file","Docker系列学习-07.Dockerfile指令详解.html.vue"]]);export{C as default};
